// node bundle.js — inline the netlist JSON and the rendered SVG into
// circuit.js so index.html works from file:// with no fetch.
const fs = require("fs");
const path = require("path");
const dir = __dirname;

const netlist = fs.readFileSync(path.join(dir, "fizzbuzz.json"), "utf8");
const svg = fs.readFileSync(path.join(dir, "fizzbuzz.svg"), "utf8");

fs.writeFileSync(path.join(dir, "circuit.js"),
    "// Generated by build.sh — do not edit. See fizzbuzz.v for the source.\n" +
    `const FIZZBUZZ_NETLIST = ${netlist.trim()};\n` +
    `const FIZZBUZZ_SVG = ${JSON.stringify(svg)};\n`);
console.log("wrote circuit.js");
